cat > /app/ars.R <<'EOF'
# Adaptive Rejection Sampling (Gilks and Wild, 1992)

as_density_function <- function(density, eval_env = parent.frame()) {
  if (is.function(density)) {
    return(density)
  }

  if (is.character(density) && length(density) == 1) {
    expr <- parse(text = density)[[1]]
    return(function(x) eval(expr, envir = list(x = x), enclos = eval_env))
  }

  if (is.expression(density) && length(density) == 1) {
    expr <- density[[1]]
    return(function(x) eval(expr, envir = list(x = x), enclos = eval_env))
  }

  stop("`density` must be a function, a character expression, or an expression.")
}

validate_integerish <- function(x, name, allow_zero = FALSE) {
  if (!is.numeric(x) || length(x) != 1 || is.na(x) || !is.finite(x)) {
    stop(sprintf("`%s` must be a finite numeric scalar.", name))
  }

  if (abs(x - round(x)) > 1e-8) {
    stop(sprintf("`%s` must be an integer value.", name))
  }

  x_int <- as.integer(round(x))
  if (allow_zero) {
    if (x_int < 0) {
      stop(sprintf("`%s` must be >= 0.", name))
    }
  } else {
    if (x_int <= 0) {
      stop(sprintf("`%s` must be > 0.", name))
    }
  }

  x_int
}

choose_default_initial <- function(lower, upper) {
  if (is.finite(lower) && is.finite(upper)) {
    span <- upper - lower
    return(c(lower + 0.25 * span, lower + 0.5 * span, lower + 0.75 * span))
  }

  if (is.finite(lower) && !is.finite(upper)) {
    return(lower + c(0.5, 1.5, 3.0))
  }

  if (!is.finite(lower) && is.finite(upper)) {
    return(upper - c(3.0, 1.5, 0.5))
  }

  c(-1, 0, 1)
}

check_vectorized_density <- function(density_fn, probe) {
  out <- tryCatch(
    density_fn(probe),
    error = function(e) {
      stop(sprintf("`density` failed on vector input: %s", conditionMessage(e)))
    }
  )

  if (!is.numeric(out)) {
    stop("`density` must return numeric values.")
  }

  if (length(out) != length(probe)) {
    stop("`density` must be vectorized and return the same length as its input.")
  }

  if (any(is.na(out))) {
    stop("`density` returned NA values on probe input.")
  }

  if (any(out < 0)) {
    stop("`density` returned negative values on probe input.")
  }
}

validate_inputs <- function(density_fn,
                            n,
                            lower,
                            upper,
                            initial,
                            max_iter,
                            concavity_tol) {
  n <- validate_integerish(n, "n", allow_zero = FALSE)
  max_iter <- validate_integerish(max_iter, "max_iter", allow_zero = FALSE)

  if (!is.numeric(lower) || length(lower) != 1 || is.na(lower)) {
    stop("`lower` must be a numeric scalar.")
  }

  if (!is.numeric(upper) || length(upper) != 1 || is.na(upper)) {
    stop("`upper` must be a numeric scalar.")
  }

  if (!(lower < upper)) {
    stop("`lower` must be strictly less than `upper`.")
  }

  if (!is.numeric(concavity_tol) || length(concavity_tol) != 1 || is.na(concavity_tol) || concavity_tol <= 0) {
    stop("`concavity_tol` must be a positive numeric scalar.")
  }

  if (is.null(initial)) {
    initial <- choose_default_initial(lower, upper)
  }

  if (!is.numeric(initial) || length(initial) < 2 || any(!is.finite(initial))) {
    stop("`initial` must contain at least two finite numeric values.")
  }

  initial <- sort(unique(as.numeric(initial)))
  if (length(initial) < 2) {
    stop("`initial` must contain at least two distinct values.")
  }

  if (any(initial <= lower) || any(initial >= upper)) {
    stop("All `initial` points must lie strictly inside (lower, upper).")
  }

  probe <- if (length(initial) <= 5) initial else initial[round(seq(1, length(initial), length.out = 5))]
  check_vectorized_density(density_fn, probe)

  list(
    n = n,
    lower = as.numeric(lower),
    upper = as.numeric(upper),
    initial = initial,
    max_iter = max_iter,
    concavity_tol = as.numeric(concavity_tol)
  )
}

make_log_density <- function(density_fn, lower, upper) {
  function(x) {
    x <- as.numeric(x)
    out <- rep(-Inf, length(x))

    inside <- is.finite(x) & x >= lower & x <= upper
    if (!any(inside)) {
      return(out)
    }

    vals <- density_fn(x[inside])
    if (!is.numeric(vals) || length(vals) != sum(inside)) {
      stop("`density` must return numeric output with same length as input.")
    }

    if (any(is.na(vals))) {
      stop("`density` returned NA values.")
    }

    if (any(vals < 0)) {
      stop("`density` returned negative values.")
    }

    if (any(is.infinite(vals))) {
      stop("`density` returned Inf values, which are not supported.")
    }

    local <- rep(-Inf, length(vals))
    positive <- vals > 0
    local[positive] <- log(vals[positive])
    out[inside] <- local

    out
  }
}

numeric_log_derivative <- function(log_density, x, lower, upper) {
  step <- 1e-5 * (1 + abs(x))
  left <- x - step
  right <- x + step

  if (left <= lower) left <- x
  if (right >= upper) right <- x

  if (left < x && right > x) {
    vals <- log_density(c(left, right))
    if (any(!is.finite(vals))) {
      stop("Failed to compute a finite central derivative of log-density.")
    }
    return((vals[2] - vals[1]) / (right - left))
  }

  if (right > x) {
    vals <- log_density(c(x, right))
    if (any(!is.finite(vals))) {
      stop("Failed to compute a finite forward derivative of log-density.")
    }
    return((vals[2] - vals[1]) / (right - x))
  }

  if (left < x) {
    vals <- log_density(c(left, x))
    if (any(!is.finite(vals))) {
      stop("Failed to compute a finite backward derivative of log-density.")
    }
    return((vals[2] - vals[1]) / (x - left))
  }

  stop("Could not compute derivative at this support point.")
}

reduce_parallel_tangents <- function(knots, hvals, slopes, slope_tol = 1e-8, intercept_tol = 1e-6) {
  if (length(knots) <= 1) {
    return(list(knots = knots, hvals = hvals, slopes = slopes))
  }

  keep <- c(1)
  for (i in 2:length(knots)) {
    j <- keep[length(keep)]
    if (abs(slopes[i] - slopes[j]) <= slope_tol) {
      bi <- hvals[i] - slopes[i] * knots[i]
      bj <- hvals[j] - slopes[j] * knots[j]
      if (abs(bi - bj) <= intercept_tol) {
        next
      }
      stop("Density appears non-log-concave: parallel tangents with different intercepts.")
    }
    keep <- c(keep, i)
  }

  list(
    knots = knots[keep],
    hvals = hvals[keep],
    slopes = slopes[keep]
  )
}

check_tail_integrability <- function(slopes, lower, upper) {
  if (!is.finite(lower) && slopes[1] <= 0) {
    stop("Upper hull is non-integrable on the left tail; choose better initial points.")
  }

  if (!is.finite(upper) && slopes[length(slopes)] >= 0) {
    stop("Upper hull is non-integrable on the right tail; choose better initial points.")
  }
}

check_discrete_concavity <- function(knots, hvals, slopes, tol) {
  if (any(diff(knots) <= 0)) {
    stop("Internal error: knots are not strictly increasing.")
  }

  if (length(slopes) > 1 && any(diff(slopes) > tol)) {
    stop("Density appears non-log-concave: tangent slopes are not non-increasing.")
  }

  if (length(knots) > 2) {
    secant <- diff(hvals) / diff(knots)
    if (any(diff(secant) > tol)) {
      stop("Density appears non-log-concave: secant slopes violate concavity.")
    }
  }
}

check_midpoint_concavity <- function(log_density, knots, hvals, tol) {
  if (length(knots) < 2) {
    return(invisible(NULL))
  }

  mids <- (knots[-length(knots)] + knots[-1]) / 2
  h_mid <- log_density(mids)
  h_line <- hvals[-length(hvals)] +
    (hvals[-1] - hvals[-length(hvals)]) *
    (mids - knots[-length(knots)]) / (knots[-1] - knots[-length(knots)])

  if (any(h_mid + tol < h_line)) {
    stop("Density appears non-log-concave: midpoint chord test failed.")
  }
}

compute_intersections <- function(knots, hvals, slopes, lower, upper, tol = 1e-10) {
  k <- length(knots)
  if (k == 1) {
    return(c(lower, upper))
  }

  z <- numeric(k + 1)
  z[1] <- lower
  z[k + 1] <- upper

  for (i in 1:(k - 1)) {
    denom <- slopes[i] - slopes[i + 1]
    if (abs(denom) <= tol) {
      b1 <- hvals[i] - slopes[i] * knots[i]
      b2 <- hvals[i + 1] - slopes[i + 1] * knots[i + 1]
      if (abs(b1 - b2) <= 1e-6) {
        stop("Internal hull issue: redundant tangents were not reduced.")
      }
      stop("Density appears non-log-concave: adjacent tangents are effectively parallel.")
    }

    numer <- hvals[i + 1] - hvals[i] - knots[i + 1] * slopes[i + 1] + knots[i] * slopes[i]
    z[i + 1] <- numer / denom
  }

  if (any(diff(z) <= tol)) {
    stop("Density appears non-log-concave: tangent intersections are not increasing.")
  }

  if (any(z[2:k] <= knots[-k] + tol) || any(z[2:k] >= knots[-1] - tol)) {
    stop("Density appears non-log-concave: tangent intersections are not bracketed by knots.")
  }

  z
}

build_state <- function(log_density,
                        initial,
                        lower,
                        upper,
                        check_log_concavity,
                        concavity_tol) {
  knots <- sort(unique(initial))
  hvals <- log_density(knots)

  if (any(!is.finite(hvals))) {
    stop("Initial points must have positive finite density inside the target domain.")
  }

  slopes <- sapply(knots, function(x) numeric_log_derivative(log_density, x, lower, upper))
  reduced <- reduce_parallel_tangents(knots, hvals, slopes)
  knots <- reduced$knots
  hvals <- reduced$hvals
  slopes <- reduced$slopes

  check_tail_integrability(slopes, lower, upper)

  if (check_log_concavity) {
    check_discrete_concavity(knots, hvals, slopes, concavity_tol)
    check_midpoint_concavity(log_density, knots, hvals, concavity_tol)
  }

  z <- compute_intersections(knots, hvals, slopes, lower, upper)

  list(knots = knots, hvals = hvals, slopes = slopes, z = z)
}

segment_integral <- function(a, b, slope, intercept, eps = 1e-12) {
  if (is.infinite(a) && is.infinite(b)) {
    stop("Upper hull is non-integrable on an unbounded segment.")
  }

  if (abs(slope) <= eps) {
    if (is.infinite(a) || is.infinite(b)) {
      stop("Upper hull is non-integrable for zero slope on an infinite interval.")
    }
    val <- exp(intercept) * (b - a)
    if (!is.finite(val) || val <= 0) {
      stop("Failed to compute finite segment weight.")
    }
    return(val)
  }

  if (is.infinite(a)) {
    if (slope <= 0) {
      stop("Upper hull is non-integrable on left tail.")
    }
    val <- exp(intercept + slope * b) / slope
    if (!is.finite(val) || val <= 0) {
      stop("Failed to compute finite left-tail segment weight.")
    }
    return(val)
  }

  if (is.infinite(b)) {
    if (slope >= 0) {
      stop("Upper hull is non-integrable on right tail.")
    }
    val <- -exp(intercept + slope * a) / slope
    if (!is.finite(val) || val <= 0) {
      stop("Failed to compute finite right-tail segment weight.")
    }
    return(val)
  }

  val <- exp(intercept) * (exp(slope * b) - exp(slope * a)) / slope
  if (!is.finite(val) || val <= 0) {
    stop("Failed to compute finite segment weight.")
  }

  val
}

compute_segment_weights <- function(state) {
  k <- length(state$slopes)
  w <- numeric(k)

  for (i in seq_len(k)) {
    intercept <- state$hvals[i] - state$slopes[i] * state$knots[i]
    w[i] <- segment_integral(state$z[i], state$z[i + 1], state$slopes[i], intercept)
  }

  w
}

draw_from_segment <- function(a, b, slope, eps = 1e-12) {
  u <- max(runif(1), .Machine$double.eps)

  if (abs(slope) <= eps) {
    if (is.infinite(a) || is.infinite(b)) {
      stop("Cannot draw from a zero-slope segment with infinite bounds.")
    }
    return(runif(1, min = a, max = b))
  }

  if (is.finite(a) && is.finite(b)) {
    ea <- exp(slope * a)
    eb <- exp(slope * b)
    return(log(ea + u * (eb - ea)) / slope)
  }

  if (!is.finite(a) && is.finite(b)) {
    if (slope <= 0) {
      stop("Invalid left-tail segment slope.")
    }
    return(b + log(u) / slope)
  }

  if (is.finite(a) && !is.finite(b)) {
    if (slope >= 0) {
      stop("Invalid right-tail segment slope.")
    }
    return(a + log1p(-u) / slope)
  }

  stop("Invalid segment bounds.")
}

sample_from_upper_hull <- function(state) {
  weights <- compute_segment_weights(state)
  seg <- sample.int(length(weights), size = 1, prob = weights)

  x <- draw_from_segment(state$z[seg], state$z[seg + 1], state$slopes[seg])
  log_upper <- state$hvals[seg] + state$slopes[seg] * (x - state$knots[seg])

  list(x = x, log_upper = log_upper, segment = seg)
}

lower_hull_value <- function(x, knots, hvals) {
  k <- length(knots)
  if (k < 2) {
    return(-Inf)
  }

  idx_match <- which(abs(knots - x) <= 1e-12)
  if (length(idx_match) > 0) {
    return(hvals[idx_match[1]])
  }

  if (x <= knots[1] || x >= knots[k]) {
    return(-Inf)
  }

  j <- findInterval(x, knots)
  if (j <= 0 || j >= k) {
    return(-Inf)
  }

  hvals[j] + (hvals[j + 1] - hvals[j]) * (x - knots[j]) / (knots[j + 1] - knots[j])
}

insert_knot <- function(state,
                        x_new,
                        h_new,
                        log_density,
                        lower,
                        upper,
                        check_log_concavity,
                        concavity_tol) {
  if (!is.finite(x_new) || !is.finite(h_new)) {
    return(state)
  }

  if (any(abs(state$knots - x_new) <= 1e-10)) {
    return(state)
  }

  knots <- sort(c(state$knots, x_new))
  hvals <- log_density(knots)

  if (any(!is.finite(hvals))) {
    stop("Encountered non-finite log-density while updating hull.")
  }

  slopes <- sapply(knots, function(x) numeric_log_derivative(log_density, x, lower, upper))
  reduced <- reduce_parallel_tangents(knots, hvals, slopes)
  knots <- reduced$knots
  hvals <- reduced$hvals
  slopes <- reduced$slopes

  check_tail_integrability(slopes, lower, upper)

  if (check_log_concavity) {
    check_discrete_concavity(knots, hvals, slopes, concavity_tol)
    check_midpoint_concavity(log_density, knots, hvals, concavity_tol)
  }

  z <- compute_intersections(knots, hvals, slopes, lower, upper)

  list(knots = knots, hvals = hvals, slopes = slopes, z = z)
}

ars <- function(density,
                n,
                lower = -Inf,
                upper = Inf,
                initial = NULL,
                max_iter = 100000,
                seed = NULL,
                check_log_concavity = TRUE,
                concavity_tol = 1e-6) {
  density_fn <- as_density_function(density, eval_env = parent.frame())
  args <- validate_inputs(
    density_fn = density_fn,
    n = n,
    lower = lower,
    upper = upper,
    initial = initial,
    max_iter = max_iter,
    concavity_tol = concavity_tol
  )

  if (!is.logical(check_log_concavity) || length(check_log_concavity) != 1 || is.na(check_log_concavity)) {
    stop("`check_log_concavity` must be TRUE or FALSE.")
  }

  if (!is.null(seed)) {
    validate_integerish(seed, "seed", allow_zero = TRUE)
    set.seed(seed)
  }

  log_density <- make_log_density(density_fn, args$lower, args$upper)
  state <- build_state(
    log_density = log_density,
    initial = args$initial,
    lower = args$lower,
    upper = args$upper,
    check_log_concavity = check_log_concavity,
    concavity_tol = args$concavity_tol
  )

  samples <- numeric(args$n)
  accepted <- 0L
  iter <- 0L

  while (accepted < args$n) {
    iter <- iter + 1L
    if (iter > args$max_iter) {
      stop("Exceeded `max_iter` before collecting all samples.")
    }

    proposal <- sample_from_upper_hull(state)
    x <- proposal$x
    log_u <- log(runif(1))

    log_lower <- lower_hull_value(x, state$knots, state$hvals)
    if (log_u <= (log_lower - proposal$log_upper)) {
      accepted <- accepted + 1L
      samples[accepted] <- x
      next
    }

    h_x <- log_density(x)
    if (!is.finite(h_x)) {
      next
    }

    stage_two_accept <- log_u <= (h_x - proposal$log_upper)

    state <- insert_knot(
      state = state,
      x_new = x,
      h_new = h_x,
      log_density = log_density,
      lower = args$lower,
      upper = args$upper,
      check_log_concavity = check_log_concavity,
      concavity_tol = args$concavity_tol
    )

    if (stage_two_accept) {
      accepted <- accepted + 1L
      samples[accepted] <- x
    }
  }

  samples
}

print_test_result <- function(test_name, pass, mean_stat = NA_real_, sd_stat = NA_real_) {
  status <- if (isTRUE(pass)) "PASS" else "FAIL"
  mean_str <- if (is.finite(mean_stat)) sprintf("%.6f", mean_stat) else "NA"
  sd_str <- if (is.finite(sd_stat)) sprintf("%.6f", sd_stat) else "NA"
  cat(sprintf("%s: %s (mean=%s, sd=%s)\n", test_name, status, mean_str, sd_str))
  isTRUE(pass)
}

test <- function() {
  results <- logical()

  cat("Running adaptive-rejection sampler tests...\n")

  # Module test: tangent intersection math for standard normal log-density.
  knots <- c(-1, 0, 1)
  hvals <- dnorm(knots, log = TRUE)
  slopes <- -knots
  z <- tryCatch(compute_intersections(knots, hvals, slopes, -Inf, Inf), error = function(e) e)
  if (inherits(z, "error")) {
    results["INTERSECTIONS_MODULE"] <- print_test_result("INTERSECTIONS_MODULE", FALSE)
  } else {
    pass <- max(abs(z[2:3] - c(-0.5, 0.5))) < 1e-6
    results["INTERSECTIONS_MODULE"] <- print_test_result("INTERSECTIONS_MODULE", pass, mean(z[2:3]), sd(z[2:3]))
  }

  invalid_n <- tryCatch({
    ars(dnorm, n = -5)
    FALSE
  }, error = function(e) TRUE)
  results["INPUT_VALIDATION_N"] <- print_test_result("INPUT_VALIDATION_N", invalid_n)

  normal_samples <- tryCatch(
    ars(density = dnorm, n = 5000, lower = -Inf, upper = Inf, seed = 123),
    error = function(e) e
  )

  if (inherits(normal_samples, "error")) {
    results["NORMAL_DISTRIBUTION"] <- print_test_result("NORMAL_DISTRIBUTION", FALSE)
  } else {
    normal_mean <- mean(normal_samples)
    normal_sd <- sd(normal_samples)
    pass <- abs(normal_mean) < 0.08 && abs(normal_sd - 1) < 0.08
    results["NORMAL_DISTRIBUTION"] <- print_test_result("NORMAL_DISTRIBUTION", pass, normal_mean, normal_sd)

    write(normal_samples, file = "/app/normal_samples.txt", ncolumns = 1)
  }

  exp_samples <- tryCatch(
    ars(density = dexp, n = 5000, lower = 0, upper = Inf, seed = 456),
    error = function(e) e
  )

  if (inherits(exp_samples, "error")) {
    results["EXPONENTIAL_DISTRIBUTION"] <- print_test_result("EXPONENTIAL_DISTRIBUTION", FALSE)
  } else {
    exp_mean <- mean(exp_samples)
    exp_sd <- sd(exp_samples)
    pass <- abs(exp_mean - 1) < 0.08 && abs(exp_sd - 1) < 0.10
    results["EXPONENTIAL_DISTRIBUTION"] <- print_test_result("EXPONENTIAL_DISTRIBUTION", pass, exp_mean, exp_sd)
  }

  bimodal <- function(x) 0.5 * dnorm(x, mean = -2, sd = 0.5) + 0.5 * dnorm(x, mean = 2, sd = 0.5)
  non_log_concave_attempt <- try(
    ars(
      density = bimodal,
      n = 200,
      lower = -6,
      upper = 6,
      initial = c(-4, -1, 1, 4),
      seed = 99
    ),
    silent = TRUE
  )

  non_log_concave_pass <- inherits(non_log_concave_attempt, "try-error") &&
    grepl("non-log-concave", tolower(as.character(non_log_concave_attempt)))
  results["NON_LOG_CONCAVE_CHECK"] <- print_test_result("NON_LOG_CONCAVE_CHECK", non_log_concave_pass)

  overall <- all(results)
  print_test_result("OVERALL", overall)
  invisible(overall)
}
EOF

